#encoding: UTF-8#!/usr/bin/env python2import cv2import osimport numpy as npimport timeimport rospyfrom pymycobot.mycobot import MyCobotfrom opencv_yolo import yolo#from VideoCapture import FastVideoCaptureimport mathfrom GrabParams import grabParamsimport basicimport argparseadd1=5add2=5parser = argparse.ArgumentParser(description='manual to this script')parser.add_argument("--debug", type=bool, default="True")args = parser.parse_args()height_bias = grabParams.height_bias  #高度偏移量coords = grabParams.coords_ready  #机械臂的初始坐标done = grabParams.done  #操作完成标志CLASSES = ("apple", "clock", "banana","cat ","bird ") #[0,1,2,3,4]class Detect_marker(object):    def __init__(self):        super(Detect_marker, self).__init__()        self.mc = MyCobot(grabParams.usb_dev, grabParams.baudrate)        self.mc.power_on()         self.yolo = yolo()        # parameters to calculate camera clipping parameters        self.x1 = self.x2 = self.y1 = self.y2 = 0        # use to calculate coord between cube and mycobot        self.sum_x1 = self.sum_x2 = self.sum_y2 = self.sum_y1 = 0        # The coordinates of the grab center point relative to the mycobot        # The coordinates of the cube relative to the mycobot        self.c_x, self.c_y = grabParams.IMG_SIZE/2, grabParams.IMG_SIZE/2        # The ratio of pixels to actual values        self.ratio = grabParams.ratio    # Grasping motion    def move(self, x, y):        global height_bias, done        coords_target = [coords[0]+int(x), coords[1]+int(y), height_bias, coords[3], coords[4], coords[5]]        basic.move_to_target_coords(coords_target, grabParams.GRAB_MOVE_SPEED)               basic.grap(True)        angles =[10.1, -22.76, -20.3, -28.74, -5.27, 57.56]        self.mc.send_angles(angles,30)                time.sleep(1.5)        done = True        print("Done")        self.mc.set_color(0,255,0)#green, arm is free    # init mycobot  #将机械臂移动到初始位置，并设置夹爪为张开状态    def init_mycobot(self):     # angles = [0, 0, 0, 0, 0, 0]        #self.mc.send_angles(angles,30)        basic.grap(False)              time.sleep(1)                 basic.move_to_target_coords(coords,grabParams.GRAB_MOVE_SPEED)      #根据图像中物体的位置和预设的偏移量，计算机械臂需要到达的实际坐标    # calculate the coords between cube and mycobot    def get_position(self, x, y):        # print "self.ratio: ", self.ratio        # return (-(x - self.c_x)*self.ratio), (-(y - self.c_y)*self.ratio)        wx = wy = 0        if grabParams.grab_direct == "front":            wx = (self.c_y - y) * self.ratio            wy = (self.c_x - x) * self.ratio        elif grabParams.grab_direct == "right":            wx = (self.c_x - x) * self.ratio            wy = (y - self.c_y) * self.ratio        return wx, wy      #用于将图像调整为模型所需的尺寸    def transform_frame(self, frame):        frame, ratio, (dw, dh) = self.yolo.letterbox(frame, (grabParams.IMG_SIZE, grabParams.IMG_SIZE))        return frame    #图像处理，适配物体识别    def transform_frame_128(self, frame):        frame, ratio, (dw, dh) = self.yolo.letterbox(frame, (128, 128))        return frame       #使用YOLO模型进行物体检测，并返回物体中心的坐标    # detect object    def obj_detect(self, img):        x=y=0        img_ori = img        img_ori = self.transform_frame(img)        img = self.transform_frame_128(img)        #加载模型        net = cv2.dnn.readNetFromONNX("/home/robuster/beetle_ai/scripts/beetle_obj.onnx")                t1 = time.time()        #输入数据处理        blob = cv2.dnn.blobFromImage(img, 1 / 255.0, (128, 128), [0, 0, 0], swapRB=True, crop=False)        net.setInput(blob)                #推理        outputs = net.forward(net.getUnconnectedOutLayersNames())[0]                #获得识别结果        boxes, classes, scores = self.yolo.yolov5_post_process_simple(outputs)        t2 = time.time()        # img_0 = cv2.cvtColor(img, cv2.COLOR_RGB2BGR)        if boxes is not None:            boxes = boxes*5            detected_class = classes[0]            self.yolo.draw_single(img_ori, boxes[0], scores[0], classes[0])            left, top, right, bottom = boxes[0]            x = int((left+right)/2)            y = int((top+bottom)/2)            # print x, y        cv2.imshow("figure",img_ori)         cv2.waitKey(10)          # Print time (inference-only)        print("time: " + str(t2-t1) + "s")                if x+y > 0:            return x, y,detected_class        else:            return None    def run(self):        self.mc.set_color(0,0,255)#blue, arm is busy        self.init_mycobot()    #调试模式下显示图像    def show_image(self, img):        if grabParams.debug and args.debug:            cv2.imshow("figure", img)            cv2.waitKey(50)     #-------------------------------------------------------------------------------------------------------------    def grap(self, flag):          if flag:            # close            # self.mc.set_gripper_state(1, 0)            self.mc.set_gripper_value(40,0)            time.sleep(1)        else:            # open            self.mc.set_gripper_state(0, 0)            time.sleep(1)    def move_to_target_coords(self,coords,speed):  #接收目标坐标 coords 和移动速度 speed，然后调用 send_coords 方法使机械臂移动到这些坐标        print("move_to_target_coords")        self.mc.send_coords(coords,speed,1)        time.sleep(2)    # Grasping motion    def run_put_down_left_1(self):              #首先将机械臂移动到目标高度，然后闭合夹爪抓取物体          # 接着移动到目标坐标，然后移动到更高的位置并张开夹爪释放物体          # 最后再次移动到目标坐标          angles_1_1 =[45.17, -56.6, -3.16, -25.4, -4.92, 57.56]        angles_1_2 =[56.95, -48.07, -12.83, -30.14, -4.21, 57.65]        coords_0  = [210, -30, 240, -175, 0, -138]        self.grap(True)           self.mc.send_angles(angles_1_1,40)        time.sleep(1)        self.grap(False)        print("open")        self.move_to_target_coords(coords_0, grabParams.GRAB_MOVE_SPEED)        time.sleep(2)    def run_put_down_left_2(self):              #首先将机械臂移动到目标高度，然后闭合夹爪抓取物体          # 接着移动到目标坐标，然后移动到更高的位置并张开夹爪释放物体          # 最后再次移动到目标坐标          angles_1_2 =[56.95, -48.07, -12.83, -30.14, -4.21, 57.65]        coords_0  = [210, -30, 240, -175, 0, -138]        self.grap(True)           self.mc.send_angles(angles_1_2,40)        time.sleep(1)        self.grap(False)        print("open")        self.move_to_target_coords(coords_0, grabParams.GRAB_MOVE_SPEED)        time.sleep(2)    def run_put_down_right_1(self):         #首先将机械臂移动到目标高度，然后闭合夹爪抓取物体      # 接着移动到目标坐标，然后移动到更高的位置并张开夹爪释放物体      # 最后再次移动到目标坐标          angles_2_1 =[-35.77, -36.21, -38.93, -11.51, -5.27, 57.65]        angles_2_2=[-29.53, -42.18, -38.84, 6.59, -4.92, 58.79]        coords_0  = [210, -30, 240, -175, 0, -138]        self.grap(True)           self.mc.send_angles(angles_2_1,40)        time.sleep(1)        self.grap(False)        print("open")        self.move_to_target_coords(coords_0, grabParams.GRAB_MOVE_SPEED)        time.sleep(2)    def run_put_down_right_2(self):         #首先将机械臂移动到目标高度，然后闭合夹爪抓取物体      # 接着移动到目标坐标，然后移动到更高的位置并张开夹爪释放物体      # 最后再次移动到目标坐标          angles_2_2=[-29.53, -42.18, -38.84, 6.59, -4.92, 58.79]        coords_0  = [210, -30, 240, -175, 0, -138]        self.grap(True)           self.mc.send_angles(angles_2_2,40)        time.sleep(1)        self.grap(False)        print("open")        self.move_to_target_coords(coords_0, grabParams.GRAB_MOVE_SPEED)        time.sleep(2)i=0left=1right=1detect = Detect_marker()detect.run()   while i<4:    cap = cv2.VideoCapture(2)    #cap = FastVideoCapture(grabParams.cap_num)    #time.sleep(0.5)     init_num = 0    nparams = 0    num = 0    miss = 0        while True:        frame = cap.read()  #从摄像头读取当前帧,如果读取成功，frame 将包含从摄像头捕获的图像数据；如果到达视频结尾或发生错误，frame 将是 None        #用于调整图像的方向，以适应特定的视觉处理需求或机械臂的视角        frame = cv2.flip(frame,0)  #这个函数用于翻转图像,第一个参数是要翻转的图像，第二个参数是翻转的编码        frame = cv2.flip(frame,1)  #在水平翻转的基础上再垂直翻转图像        detect_result = detect.obj_detect(frame)        if detect_result is None:                       continue        else:                        x, y ,class_detected= detect_result            real_x, real_y = detect.get_position(x, y)#传入计算出来的x，y值得到真实要运动到的x，y值            coords_now = basic.get_coords()            if len(coords_now) == 6:                coords = coords_now            detect.move(real_x + grabParams.x_bias, real_y + grabParams.y_bias)            print("class_detected:",class_detected)            break    cap.release()    cv2.destroyAllWindows()        if i == 0:        add1=class_detected    if detect_result is not None and class_detected== add1 and left==1:        detect.run_put_down_letf_1()        left+=1    else:        detect.run_put_down_right_1()    if detect_result is not None and class_detected== add1 and left==2:        detect.run_put_down_letf_2()    else:        detect.run_put_down_right_2()            i+=1